import{c as h,S as a,j as i,m as t}from"./chunks/framework.8aa1YH_s.js";const m=JSON.parse('{"title":"Chương học & Chuyên đề","description":"","frontmatter":{},"headers":[],"relativePath":"admin/chuong-chuyen-de.md","filePath":"admin/chuong-chuyen-de.md","lastUpdated":0}'),c={name:"admin/chuong-chuyen-de.md"};function l(o,n,e,g,r,s){return a(),i("div",null,[...n[0]||(n[0]=[t(`<h1 id="chuong-hoc-chuyen-đe" tabindex="-1">Chương học &amp; Chuyên đề <a class="header-anchor" href="#chuong-hoc-chuyen-đe" aria-label="Permalink to “Chương học &amp; Chuyên đề”">​</a></h1><p>Chương học (Module) và Chuyên đề (Thematic) là 2 cấp tổ chức nội dung <strong>bên trong</strong> một khóa học.</p><p><strong>Đường dẫn (danh mục):</strong></p><ul><li>Danh mục chương học: <code>https://lamsonedutech.vn/admin/thematic/cate</code></li><li>Danh mục chuyên đề: <code>https://lamsonedutech.vn/admin/thematic/thematic</code></li><li>Trong khóa: vào chi tiết khóa → tab Nội dung.</li></ul><h2 id="khai-niem" tabindex="-1">Khái niệm <a class="header-anchor" href="#khai-niem" aria-label="Permalink to “Khái niệm”">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Khóa học</span></span>
<span class="line"><span>└── Chương 1</span></span>
<span class="line"><span>    ├── Chuyên đề 1.1</span></span>
<span class="line"><span>    │   ├── Bài giảng a</span></span>
<span class="line"><span>    │   └── Đề kiểm tra</span></span>
<span class="line"><span>    └── Chuyên đề 1.2</span></span>
<span class="line"><span>└── Chương 2</span></span>
<span class="line"><span>    ...</span></span></code></pre></div><ul><li><strong>Chương học</strong> = nhóm chuyên đề lớn (vd &quot;Hàm số bậc 2&quot;, &quot;Đọc hiểu văn bản&quot;).</li><li><strong>Chuyên đề</strong> = bài học nhỏ trong chương (vd &quot;Tìm tập xác định&quot;, &quot;Đỉnh parabol&quot;).</li></ul><h2 id="tao-chuong-trong-khoa" tabindex="-1">Tạo chương trong khóa <a class="header-anchor" href="#tao-chuong-trong-khoa" aria-label="Permalink to “Tạo chương trong khóa”">​</a></h2><ol><li>Vào chi tiết khóa học → tab <strong>Nội dung</strong>.</li><li>Bấm <strong>Thêm chương</strong>.</li><li>Điền: <ul><li><strong>Tên chương</strong></li><li><strong>Số thứ tự</strong> (định vị trên cây nội dung)</li><li><strong>Mô tả ngắn</strong></li><li>(Tùy chọn) <strong>Có yêu cầu hoàn thành chương trước mới mở khóa chương này?</strong></li></ul></li><li>Lưu.</li></ol><h2 id="tao-chuyen-đe-trong-chuong" tabindex="-1">Tạo chuyên đề trong chương <a class="header-anchor" href="#tao-chuyen-đe-trong-chuong" aria-label="Permalink to “Tạo chuyên đề trong chương”">​</a></h2><ol><li>Bấm vào chương vừa tạo → <strong>Thêm chuyên đề</strong>.</li><li>Điền: <ul><li><strong>Tên chuyên đề</strong></li><li><strong>Số thứ tự</strong></li><li><strong>Mô tả</strong></li><li><strong>Loại chuyên đề</strong> (Lý thuyết / Bài tập / Luyện đề / Tổng ôn …) — tùy hệ thống.</li></ul></li><li>Lưu.</li></ol><h2 id="them-noi-dung-vao-chuyen-đe" tabindex="-1">Thêm nội dung vào chuyên đề <a class="header-anchor" href="#them-noi-dung-vao-chuyen-đe" aria-label="Permalink to “Thêm nội dung vào chuyên đề”">​</a></h2><p>Trong chuyên đề có 2 loại nội dung chính:</p><h3 id="bai-giang" tabindex="-1">Bài giảng <a class="header-anchor" href="#bai-giang" aria-label="Permalink to “Bài giảng”">​</a></h3><ul><li>Bấm <strong>Thêm bài giảng</strong>.</li><li>Có thể chọn: <ul><li>Bài giảng đã có trong <a href="./bai-giang">Danh mục bài giảng</a> → liên kết.</li><li>Tạo bài mới ngay tại đây.</li></ul></li><li>Bài giảng có thể là video, văn bản, file PDF, slide.</li></ul><h3 id="đe-kiem-tra-cuoi-chuyen-đe" tabindex="-1">Đề kiểm tra cuối chuyên đề <a class="header-anchor" href="#đe-kiem-tra-cuoi-chuyen-đe" aria-label="Permalink to “Đề kiểm tra cuối chuyên đề”">​</a></h3><ul><li>Bấm <strong>Thêm đề kiểm tra</strong>.</li><li>Có thể: <ul><li>Chọn đề từ <a href="./de-on-khoa-hoc">Đề ôn khóa học</a>.</li><li>Tạo đề mới ngay (chọn câu hỏi từ <a href="./danh-muc-cau-hoi">Danh mục câu hỏi</a>).</li></ul></li><li>Cấu hình: <ul><li>Thời gian làm bài</li><li>Số câu, điểm tối đa</li><li>Số lần làm lại</li><li>Có hiển thị đáp án sau khi nộp?</li></ul></li></ul><h2 id="quan-ly-danh-muc-chuong-chuyen-đe" tabindex="-1">Quản lý danh mục Chương / Chuyên đề <a class="header-anchor" href="#quan-ly-danh-muc-chuong-chuyen-đe" aria-label="Permalink to “Quản lý danh mục Chương / Chuyên đề”">​</a></h2><p>Trong các trang <code>https://lamsonedutech.vn/admin/thematic/cate</code> và <code>https://lamsonedutech.vn/admin/thematic/thematic</code>, bạn có:</p><ul><li>Bảng danh sách toàn hệ thống.</li><li>Lọc theo khóa học, theo khung chương trình.</li><li>Cho phép tạo các <strong>chương / chuyên đề &quot;dùng chung&quot;</strong> rồi gán vào nhiều khóa khác nhau.</li></ul><h2 id="sap-xep-đoi-thu-tu" tabindex="-1">Sắp xếp / Đổi thứ tự <a class="header-anchor" href="#sap-xep-đoi-thu-tu" aria-label="Permalink to “Sắp xếp / Đổi thứ tự”">​</a></h2><ul><li>Trong trang chi tiết khóa, kéo-thả mục cần đổi vị trí.</li><li>Hoặc chỉnh trường <strong>Số thứ tự</strong> ở từng mục.</li></ul><h2 id="khoa-mo-khoa-chuyen-đe-theo-lo-trinh" tabindex="-1">Khóa / Mở khóa chuyên đề theo lộ trình <a class="header-anchor" href="#khoa-mo-khoa-chuyen-đe-theo-lo-trinh" aria-label="Permalink to “Khóa / Mở khóa chuyên đề theo lộ trình”">​</a></h2><p>Tùy cấu hình khóa, học viên có thể bị <strong>buộc học theo thứ tự</strong>:</p><ul><li>Phải xem hết bài giảng → mới làm được bài kiểm tra.</li><li>Phải đạt điểm tối thiểu của bài kiểm tra → mới mở chuyên đề tiếp theo.</li><li>Phải hoàn thành chương → mới mở chương kế.</li></ul><p>Cấu hình ở cấp khóa hoặc cấp chuyên đề.</p><h2 id="xoa" tabindex="-1">Xóa <a class="header-anchor" href="#xoa" aria-label="Permalink to “Xóa”">​</a></h2><ul><li><strong>Xóa chuyên đề:</strong> học viên sẽ mất tiến độ liên quan. Hạn chế khi đã có người học.</li><li><strong>Xóa chương:</strong> kéo theo xóa chuyên đề con. Cẩn trọng cao.</li></ul><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Tôi đổi tên chuyên đề - học viên có thấy ngay không?</strong> → Có, hệ thống đồng bộ ngay. Lịch sử làm bài vẫn giữ ID nội bộ nên không bị mất.</p><p><strong>Có thể copy chuyên đề từ khóa này sang khóa khác?</strong> → Có (nếu hệ thống bật chức năng). Dùng nút <strong>Sao chép → Vào khóa…</strong>.</p><p><strong>Học viên báo &quot;không mở được chuyên đề 3 dù đã học chuyên đề 2&quot;.</strong> → Có thể là yêu cầu đạt điểm tối thiểu của bài kiểm tra chuyên đề 2 chưa thỏa. Kiểm tra cấu hình mở khóa.</p>`,32)])])}const d=h(c,[["render",l]]);export{m as __pageData,d as default};
